package com.hospital.management.controller.admission;import com.hospital.management.model.Bed;import com.hospital.management.service.*;import com.hospital.management.service.impl.BedServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.*;@WebServlet("/admin/beds/view")public class BedViewServlet extends HttpServlet{private final BedService s;public BedViewServlet(){this(new BedServiceImpl());}BedViewServlet(BedService s){this.s=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=AdmissionRequest.id(q.getParameter("id"));if(id==null){r.sendError(400);return;}Bed x=s.getBed(id).orElse(null);if(x==null){r.sendError(404);return;}q.setAttribute("bed",x);q.getRequestDispatcher("/WEB-INF/views/admin/beds/view.jsp").forward(q,r);}}
